instance Aeson.ToJSON Field where
  toJSON msg =
    jsonObject
      [ "type" .=: msg.fieldType
      , "name" .=: msg.fieldName
      , "id" .=: msg.fieldId
      , "parentId" .=: msg.fieldParentId
      , "logicalType" .=: msg.fieldLogicalType
      , "nullable" .=: msg.fieldNullable
      , bytesMapFieldToJSON "metadata" msg.fieldMetadata
      , "unenforcedPrimaryKey" .=: msg.fieldUnenforcedPrimaryKey
      , "unenforcedPrimaryKeyPosition" .=: msg.fieldUnenforcedPrimaryKeyPosition
      , "encoding" .=: msg.fieldEncoding
      , "dictionary" .=: msg.fieldDictionary
      , "extensionName" .=: msg.fieldExtensionName
      ]


instance Aeson.FromJSON Field where
  parseJSON = Aeson.withObject "Field" $ \obj -> do
    fld_fieldType <- parseFieldMaybe obj "type"
    fld_fieldName <- parseFieldMaybe obj "name"
    fld_fieldId <- parseFieldMaybe obj "id"
    fld_fieldParentId <- parseFieldMaybe obj "parentId"
    fld_fieldLogicalType <- parseFieldMaybe obj "logicalType"
    fld_fieldNullable <- parseFieldMaybe obj "nullable"
    fld_fieldMetadata <- parseBytesMapFieldMaybe obj "metadata"
    fld_fieldUnenforcedPrimaryKey <- parseFieldMaybe obj "unenforcedPrimaryKey"
    fld_fieldUnenforcedPrimaryKeyPosition <- parseFieldMaybe obj "unenforcedPrimaryKeyPosition"
    fld_fieldEncoding <- parseFieldMaybe obj "encoding"
    fld_fieldDictionary <- parseFieldMaybe obj "dictionary"
    fld_fieldExtensionName <- parseFieldMaybe obj "extensionName"
    pure
      defaultField
        { fieldType = maybe (fieldType defaultField) id fld_fieldType
        , fieldName = maybe (fieldName defaultField) id fld_fieldName
        , fieldId = maybe (fieldId defaultField) id fld_fieldId
        , fieldParentId = maybe (fieldParentId defaultField) id fld_fieldParentId
        , fieldLogicalType = maybe (fieldLogicalType defaultField) id fld_fieldLogicalType
        , fieldNullable = maybe (fieldNullable defaultField) id fld_fieldNullable
        , fieldMetadata = maybe (fieldMetadata defaultField) id fld_fieldMetadata
        , fieldUnenforcedPrimaryKey = maybe (fieldUnenforcedPrimaryKey defaultField) id fld_fieldUnenforcedPrimaryKey
        , fieldUnenforcedPrimaryKeyPosition = maybe (fieldUnenforcedPrimaryKeyPosition defaultField) id fld_fieldUnenforcedPrimaryKeyPosition
        , fieldEncoding = maybe (fieldEncoding defaultField) id fld_fieldEncoding
        , fieldDictionary = maybe (fieldDictionary defaultField) id fld_fieldDictionary
        , fieldExtensionName = maybe (fieldExtensionName defaultField) id fld_fieldExtensionName
